import 'dart:async';import 'package:flutter/material.dart';import '../../core/app_colors/app_colors.dart';import '../../core/app_icons/app_icons.dart';import '../../widgets/app/facebook_logo.dart';import '../login/view.dart';part 'units/meta_logo.dart';// i prefer to use custom splash screen// flutter_native_splash can not be customized especially for icon sizes// also if running logic in splash screen, flutter_native_splash is not recommendedclass SplashView extends StatefulWidget {  const SplashView({super.key});  @override  State<SplashView> createState() => _SplashViewState();}class _SplashViewState extends State<SplashView> {  Timer? timer;  @override  void initState() {    timer = Timer(const Duration(seconds: 3), () {      Navigator.of(        context,      ).pushReplacement(MaterialPageRoute(builder: (context) => const LoginView()));    });    super.initState();  }  @override  void dispose() {    timer?.cancel();    super.dispose();  }  @override  Widget build(BuildContext context) {    return Scaffold(      body: const Stack(        children: [FacebookLogo(), SizedBox(height: 200), MetaLogo()],      ),    );  }}